# Allocation health check: identify over-allocated skills
from dataclasses import dataclass, field
from typing import List

@dataclass
class SkillCapacity:
    skill: str
    available_ftes: float

@dataclass
class InitiativeDemand:
    initiative_id: str
    priority: int
    demands: list  # [{"skill": str, "ftes": float}]

def allocate(capacities: List[SkillCapacity], initiatives: List[InitiativeDemand]):
    supply = {c.skill: c.available_ftes for c in capacities}
    allocation = {}
    gaps = []

    for initiative in sorted(initiatives, key=lambda x: x.priority):
        allocation[initiative.initiative_id] = []
        for d in initiative.demands:
            skill, needed = d["skill"], d["ftes"]
            available = supply.get(skill, 0)
            if available >= needed:
                supply[skill] -= needed
                allocation[initiative.initiative_id].append({
                    "skill": skill, "allocated": needed, "gap": 0
                })
            else:
                gap = needed - available
                supply[skill] = 0
                allocation[initiative.initiative_id].append({
                    "skill": skill, "allocated": available, "gap": gap
                })
                gaps.append({
                    "initiative": initiative.initiative_id,
                    "skill": skill,
                    "gap_ftes": gap
                })

    return allocation, gaps

# Example usage
capacities = [
    SkillCapacity("ml-training", 4.8),
    SkillCapacity("api-backend", 3.2),
    SkillCapacity("data-analysis", 0.8),
]
initiatives = [
    InitiativeDemand("contract-ai", 1, [
        {"skill": "ml-training", "ftes": 1.5},
        {"skill": "api-backend", "ftes": 1.0}
    ]),
    InitiativeDemand("fraud-v2", 2, [
        {"skill": "ml-training", "ftes": 1.0},
        {"skill": "data-analysis", "ftes": 0.5}
    ]),
    InitiativeDemand("onboarding-copilot", 3, [
        {"skill": "ml-training", "ftes": 2.5},
        {"skill": "api-backend", "ftes": 1.5}
    ]),
]
alloc, gaps = allocate(capacities, initiatives)
print("Gaps:", gaps)
# Output: onboarding-copilot has 1.2 FTE gap in ml-training
